void UpdateElectricBaseboardOff(Real64 &LoadMet,
                                    Real64 &QBBCap,
                                    Real64 &RadHeat,
                                    Real64 &QBBElecRadSrc,
                                    Real64 &ElecUseRate,
                                    Real64 &AirOutletTemp,
                                    Real64 const AirInletTemp)
    {

        // SUBROUTINE INFORMATION:
        //       AUTHOR         Rick Strand
        //       DATE WRITTEN   August 2017

        // PURPOSE OF THIS SUBROUTINE: Zero out appropriate system variables when it is off

        QBBCap = 0.0;
        LoadMet = 0.0;
        RadHeat = 0.0;
        AirOutletTemp = AirInletTemp;
        QBBElecRadSrc = 0.0;
        ElecUseRate = 0.0;
    }

void UpdateElectricBaseboardOn(
        Real64 &AirOutletTemp, Real64 &ElecUseRate, Real64 const AirInletTemp, Real64 const QBBCap, Real64 const CapacitanceAir, Real64 const Effic)
    {

        // SUBROUTINE INFORMATION:
        //       AUTHOR         Rick Strand
        //       DATE WRITTEN   August 2017

        // PURPOSE OF THIS SUBROUTINE: System is on, so calculate some of the result variables

        AirOutletTemp = AirInletTemp + QBBCap / CapacitanceAir;
        // This could be utilized somehow or even reported so the data structures are left in place
        // The Baseboard electric Load is calculated using the efficiency
        ElecUseRate = QBBCap / Effic;
    }

void InvOrdinalDay(int const Number, int &PMonth, int &PDay, int const LeapYr)
{

    // SUBROUTINE INFORMATION:
    //       AUTHOR         Linda Lawrie
    //       DATE WRITTEN   December 1999

    // PURPOSE OF THIS SUBROUTINE:
    // This subroutine performs and inverse Julian Day
    // calculation, using an input JulianDay and returning
    // appropriate Month and Day.

    // SUBROUTINE PARAMETER DEFINITIONS:
    static constexpr std::array<int, 13> EndOfMonth = {0, 31, 59, 90, 120, 151, 181, 212, 243, 273, 304, 334, 365};

    // SUBROUTINE LOCAL VARIABLE DECLARATIONS:
    int WMonth;
    int LeapAddPrev;
    int LeapAddCur;

    if (Number < 0 || Number > 366) {
        return;
    }
    for (WMonth = 1; WMonth <= 12; ++WMonth) {
        if (WMonth == 1) {
            LeapAddPrev = 0;
            LeapAddCur = 0;
        } else if (WMonth == 2) {
            LeapAddPrev = 0;
            LeapAddCur = LeapYr;
        } else {
            LeapAddPrev = LeapYr;
            LeapAddCur = LeapYr;
        }
        if (Number > (EndOfMonth[WMonth - 1] + LeapAddPrev) && Number <= (EndOfMonth[WMonth] + LeapAddCur)) {
            break;
        }
    }
    PMonth = WMonth;
    PDay = Number - (EndOfMonth[WMonth - 1] + LeapAddCur);
}

void ParseTime(Real64 const Time, // Time value in seconds
               int &Hours,        // Number of hours
               int &Minutes,      // Number of minutes < 60
               Real64 &Seconds    // Number of seconds < 60
)
{
    // FUNCTION INFORMATION:
    //       AUTHOR         Dimitri Curtil
    //       DATE WRITTEN   January 2005

    // PURPOSE OF THIS FUNCTION:
    // This subroutine decomposes a time value specified in seconds
    // into a triplet { hours : minutes : seconds } such that
    // - minutes < 60
    // - seconds < 60

    // SUBROUTINE LOCAL VARIABLE DECLARATIONS:
    int constexpr MinToSec = 60;
    int constexpr HourToSec = 60 * 60;

    // Get number of hours
    // This might undershoot the actual number of hours. See DO WHILE loop.
    Hours = int(Time) / HourToSec;

    // Compute remainder in seconds
    Real64 Remainder = (Time - Hours * HourToSec);

    // Compute minutes
    Minutes = int(Remainder) / MinToSec;

    // Compute remainder in seconds
    Remainder -= Minutes * MinToSec;

    // Compute seconds
    Seconds = Remainder;
}

void NormalizePhiTheta(Real64 &phi, Real64 &theta)
{

    while (phi > 2 * Constant::Pi) {
        phi -= 2 * Constant::Pi;
    }
    if (phi > Constant::Pi) {
        phi = 2 * Constant::Pi - phi;
    }

    while (theta > 2 * Constant::Pi) {
        theta -= 2 * Constant::Pi;
    }
    if (theta > Constant::Pi) {
        theta = 2 * Constant::Pi - theta;
    }
}

void GetPhiThetaIndices(Real64 phi, Real64 theta, Real64 dPhi, Real64 dTheta, int &iPhi1, int &iPhi2, int &iTheta1, int &iTheta2)
{
    iPhi1 = int(phi / dPhi);
    iPhi2 = (iPhi1 == maxIPhi - 1) ? iPhi1 : iPhi1 + 1;
    iTheta1 = int(theta / dTheta);
    iTheta2 = (iTheta1 == maxITheta - 1) ? iTheta1 : iTheta1 + 1;
}

void GetProfIndices(Real64 profAng, int &idxLo, int &idxHi)
{
    idxLo = int((profAng + Constant::PiOvr2) / dProfAng) + 1;
    idxHi = std::min(MaxProfAngs, idxLo + 1);
}

void GetSlatIndicesInterpFac(Real64 slatAng, int &idxLo, int &idxHi, Real64 &interpFac)
{
    idxLo = int(slatAng / dSlatAng);
    idxHi = std::min(MaxSlatAngs, idxLo + 1);
    interpFac = (slatAng - (idxLo * dSlatAng)) / dSlatAng;
}
